-- 좌석 (1F: 가/나/다, 2F: 라/마/바, 각 10행x10열 = 총 600석)
-- ============================================================

-- ============================================================
SELECT s.id, st.id,
    (SELECT sg.id FROM SHOW_GRADES sg WHERE sg.show_id = s.id AND sg.sort_order = CASE WHEN st.id <= 150 THEN 1 WHEN st.id <= 300 THEN 2 WHEN st.id <= 450 THEN 3 ELSE 4 END),
    '2026-01-01 10:00:00', '시드', 'ACTIVE'
FROM SHOWS s CROSS JOIN SEATS st;

-- ============================================================
-- 회차-좌석 매핑 (INSERT...SELECT)
-- ============================================================
SELECT p.id, st.id,
    CASE WHEN MOD(st.id * 7 + p.id * 3, 10) < 3 THEN 'RESERVED' ELSE 'AVAILABLE' END,
    (SELECT sg.price FROM SHOW_GRADES sg WHERE sg.show_id = p.show_id AND sg.sort_order = CASE WHEN st.id <= 150 THEN 1 WHEN st.id <= 300 THEN 2 WHEN st.id <= 450 THEN 3 ELSE 4 END),
    '2026-01-01 10:00:00', '시드', 'ACTIVE'
FROM PERFORMANCES p CROSS JOIN SEATS st;